import React, { useEffect, useRef, useState } from "react";
import { Rocket, Eye, History, Telescope, ChevronRight, ArrowRightToLine, Mountain, BookOpen } from "lucide-react";

// Constantes de datos con iconos
const mainSections = [
  {
    id: "objective",
    title: "OBJETIVO",
    displayTitle: "Objetivo",
    icon: ArrowRightToLine,
    body: ( 
      <p> 
        Preservamos, organizamos y exhibimos el patrimonio corporativo de empresas bolivianas con más de 40 años de trayectoria. 
        Digitalizamos archivos, certificamos hitos históricos y creamos narrativas vivas que honran el legado mientras inspiran 
        a la próxima generación de líderes empresariales. 
      </p> 
    ),
    image: '/media/historiapage/bolivia.jpg', 
  },
  {
    id: "mission",
    title: "MISIÓN",
    displayTitle: "Misión",
    icon: Mountain,
    body: ( 
      <p> 
        Proteger la memoria de la empresa boliviana mediante documentación rigurosa, narrativas históricas cuidadosas y diseño atemporal, 
        haciendo que el viaje de cada empresa sea accesible, verificable y bellamente preservado para el futuro. 
      </p> 
    ),
    image: '/media/historiapage/AGRO.jpg',
  },
  {
    id: "vision",
    title: "VISIÓN",
    displayTitle: "Visión",
    icon: Eye,
    body: ( 
      <p> 
        Un archivo nacional prestigioso donde la historia de la excelencia empresarial sea atesorada, sirviendo como referencia para 
        investigadores, emprendedores y familias que elevan el legado de la industria boliviana en el escenario mundial. 
      </p> 
    ),
    image: '/media/historiapage/flamingob.jpg',
  },
  {
    id: "origin",
    title: "ORIGEN",
    displayTitle: "Origen",
    icon: History,
    body: ( 
      <p> 
        Nacidos del compromiso con la memoria cultural, surgimos cuando historiadores, archiveros e innovadores se unieron alrededor 
        de una idea simple: si no documentamos nuestras empresas hoy, las generaciones futuras heredarán silencio donde debería haber legado. 
      </p> 
    ),
    image: '/media/historiapage/salarB.jpg', 
  },
];

const howItStartedSection = {
  id: "how",
  title: "NUESTRA HISTORIA",
  displayTitle: "Nuestra Historia",
  icon: BookOpen,
  body: (
    <div className="w-full">
      <div className="relative py-6 px-4 md:px-0">
        <div className="hidden md:block absolute left-0 right-0 top-10 h-0.5 bg-white" />
        <div className="block md:hidden absolute left-6 top-6 bottom-0 w-px bg-gradient-to-b from-transparent via-[#072D42]/20 to-transparent" />
        <ol className="relative z-10 flex flex-col md:flex-row gap-12 md:gap-10 lg:gap-16">
          {[
            { year: "1980s", text: "Primeros archivos fundacionales recolectados en diversos sectores empresariales." },
            { year: "1990s", text: "Primeras alianzas público-privadas para la preservación histórica." },
            { year: "2000s", text: "Programa de digitalización y establecimiento de estándares de certificación." },
            { year: "2010s", text: "Exhibiciones interactivas y expansión institucional a nivel nacional." },
            { year: "Actualidad", text: "Una plataforma viva que conecta el legado con la innovación empresarial." },
          ].map((m) => (
            <li key={m.year} className="md:min-w-[10rem] md:text-center">
              <div className="hidden md:flex flex-col items-center gap-3">
                <div className="relative">
                  <span className="block w-3 h-3 rounded-full border-2 border-[#072D42]" />
                </div>
                <div className="text-sm font-light tracking-wide">
                  <span className="font-serif text-lg block mb-1 text-[#072D42]">{m.year}</span>
                  <span className="block max-w-[16rem] text-xs leading-tight text-[#072D42]/80">{m.text}</span>
                </div>
              </div>
              <div className="flex md:hidden items-start gap-4">
                <div className="relative pt-1.5">
                  <span className="block w-3 h-3 rounded-full border-2 border-[#072D42]" />
                </div>
                <div className="text-sm font-light tracking-wide">
                  <span className="font-serif text-lg block mb-1 text-[#072D42]">{m.year}</span>
                  <span className="block text-xs leading-tight text-[#072D42]/80">{m.text}</span>
                </div>
              </div>
            </li>
          ))}
        </ol>
      </div>
    </div>
  ),
};

const allSections = [...mainSections, howItStartedSection];
const SCROLL_OFFSET = 9.375;

// Estilos de fuentes
const fontStyles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Montserrat:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;1,100;1,200;1,300;1,400&family=Inter:wght@100;200;300;400;500;600;700&display=swap');
  
  .font-playfair {
    font-family: 'Playfair Display', serif;
  }
  
  .font-montserrat {
    font-family: 'Montserrat', sans-serif;
  }
  
  .font-inter {
    font-family: 'Inter', sans-serif;
  }
`;

const AboutUsPage = () => {
  const [active, setActive] = useState(allSections[0].id);
  const [revealedSections, setRevealedSections] = useState({});
  const sectionRefs = useRef({});
  const [isHeaderShrunk, setIsHeaderShrunk] = useState(false);
  const [scrollY, setScrollY] = useState(0);
  const tickingRef = useRef(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Insertar estilos en el head del documento
  useEffect(() => {
    const styleElement = document.createElement('style');
    styleElement.textContent = fontStyles;
    document.head.appendChild(styleElement);
    
    return () => {
      document.head.removeChild(styleElement);
    };
  }, []);

  // ⚡ OPTIMIZADO: Scroll con throttling
  useEffect(() => {
    const handleScroll = () => {
      setIsHeaderShrunk(window.scrollY > 100);
      
      if (!tickingRef.current) {
        requestAnimationFrame(() => {
          setScrollY(window.scrollY);
          tickingRef.current = false;
        });
        tickingRef.current = true;
      }
    };
    
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // ⚡ OPTIMIZADO: IntersectionObserver más eficiente
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setActive(entry.target.id);
            setRevealedSections(prev => ({ ...prev, [entry.target.id]: true }));
          }
        });
      },
      { 
        root: null, 
        threshold: 0.3,
        rootMargin: "-10% 0px -10% 0px"
      },
    );

    allSections.forEach((s) => {
      const el = sectionRefs.current[s.id];
      if (el) observer.observe(el);
    });
    
    return () => observer.disconnect();
  }, []);

  const scrollTo = (e, id) => {
    e.preventDefault();
    const el = sectionRefs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.scrollY;
    const offsetPosition = elementPosition - (SCROLL_OFFSET * 16);
    
    window.scrollTo({ top: offsetPosition, behavior: "smooth" });
    setActive(id);
    setIsMobileMenuOpen(false);
  };

  const parallaxStyle = {
    transform: `translate3d(0, ${scrollY * 0.4}px, 0)`
  };

  // Componente para el icono de fondo a la derecha (solo para mainSections)
  const BackgroundIcon = ({ icon: Icon, className = "" }) => {
    return (
      <div className={`absolute right-4 top-1/2 -translate-y-1/2 flex items-center justify-center pointer-events-none ${className}`}>
        <Icon className="w-32 h-32 md:w-48 md:h-48 opacity-10 text-[#072D42] group-hover:text-white transition-colors duration-500" />
      </div>
    );
  };

  return (
    <div className="bg-[#FAF8F5] text-[#072D42] min-h-screen font-sans [&_a]:no-underline [&_a:hover]:no-underline">
      {/* HEADER CON EFECTO PARALLAX OPTIMIZADO */}
      <div className="h-[20vh] min-h-[25rem] max-h-[50rem] mb-9 overflow-hidden relative">
        <header className="relative h-full">
          <div 
            className="absolute inset-0 w-full h-full"
            style={parallaxStyle}
          >
            <img 
              src="/media/historiapage/salarB.jpg"
              alt="Fondo del Archivo Histórico Empresarial Boliviano"
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black/45"></div>
          </div>
          
          <div className="relative z-30 p-20 lg:p-48 text-white h-full flex flex-col justify-center">
            <h1 className="font-playfair text-5xl lg:text-9xl font-normal leading-[0.9] tracking-tight mb-4 text-white">
              Nosotros
            </h1>
            
            <div className="mb-6">
              <h2 className="font-montserrat text-2xl lg:text-3xl font-light tracking-[0.2em] uppercase text-white/95 mb-3">
                Archivo Histórico Empresarial
              </h2>
              <div className="h-px w-32 bg-white/70 mb-4"></div>
            </div>
            
            <p className="font-inter text-xl lg:text-2xl font-extralight tracking-wide max-w-2xl text-white/90 leading-relaxed">
              Registrando la evolución del sector empresarial boliviano y preservando legados de más de 40 años.
            </p>
          </div>
        </header>
      </div>

      <main className="px-4 sm:px-6 lg:px-10 py-0">
        {/* BOTÓN MENÚ MÓVIL - SOLO EN DISPOSITIVOS PEQUEÑOS */}
        <div className="block lg:hidden mb-6">
          <button
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            className="w-full flex items-center justify-between py-3 px-4 bg-white rounded-lg border border-[#9298A6]/30 shadow-sm"
          >
            <span className="font-montserrat text-sm font-medium text-[#072D42]">
              Navegación
            </span>
            <ChevronRight 
              className={`w-4 h-4 text-[#072D42] transition-transform duration-300 ${
                isMobileMenuOpen ? 'rotate-90' : 'rotate-0'
              }`} 
            />
          </button>
        </div>

        <div className="flex flex-col lg:flex-row gap-8 lg:gap-16 relative">
          {/* ASIDE SIEMPRE AL 25% DEL ANCHO HORIZONTAL */}
          <aside className={`
            ${isMobileMenuOpen ? 'block' : 'hidden lg:block'}
            w-full lg:w-1/4
            relative
            transition-all duration-300 ease-in-out
            ${isMobileMenuOpen ? 'mb-6' : ''}
          `}>
            <nav className={`
              bg-white rounded-xl shadow-sm border border-[#9298A6]/20
              overflow-hidden
              ${isMobileMenuOpen ? 'animate-fadeIn' : ''}
            `}>
              {allSections.map((s) => (
                <a
                  key={s.id}
                  href={`#${s.id}`}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`
                    relative group flex items-center justify-between py-4 px-5 
                    transition-all duration-300 ease-out
                    border-b border-[#9298A6]/10 last:border-b-0
                    hover:bg-[#072D42]/5
                    ${
                      active === s.id 
                        ? 'bg-[#072D42]/10 font-semibold text-[#072D42] border-l-4 border-l-[#072D42]'
                        : 'font-light text-[#072D42]/80 hover:text-[#072D42]'
                    }
                  `}
                >
                  <div className="flex items-center gap-3 flex-1 min-w-0">
                    <s.icon className={`w-4 h-4 flex-shrink-0 transition-colors duration-300 ${
                      active === s.id ? 'text-[#072D42]' : 'text-[#072D42]/60 group-hover:text-[#072D42]'
                    }`} />
                    
                    <span className={`
                      font-montserrat text-sm lg:text-base tracking-wide truncate
                      ${active === s.id ? 'font-semibold' : 'font-normal'}
                    `}>
                      {s.title}
                    </span>
                  </div>
                  
                  <div className={`
                    transition-all duration-300 transform
                    ${active === s.id ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-2 group-hover:opacity-100 group-hover:translate-x-0'}
                  `}>
                    <ChevronRight className="w-3 h-3 text-[#072D42]" />
                  </div>
                </a>
              ))}
            </nav>
          </aside>

          {/* CONTENIDO PRINCIPAL - SIEMPRE 75% DEL ANCHO */}
          <section className={`
            w-full lg:w-3/4
            transition-all duration-300
            flex flex-col gap-12 md:gap-16
          `}>
            {mainSections.map((s) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (sectionRefs.current[s.id] = el)}
                className={`
                  scroll-mt-24 bg-white rounded-xl shadow-md border border-[#072D42]/20 
                  hover:border-[#072D42] hover:shadow-lg 
                  overflow-hidden group hover:bg-[#072D42]
                  transform transition-all duration-500 ease-out relative
                  ${revealedSections[s.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}
                `}
              >
                <BackgroundIcon icon={s.icon} />
                
                <div className={`transition-opacity duration-300 relative z-10 ${active === s.id ? "opacity-100" : "opacity-80"}`}>
                  <div className="flex flex-col md:flex-row">
                    {s.image && (
                      <div className="md:w-2/5 flex order-1 md:order-1 overflow-hidden">
                        <img 
                          src={s.image} 
                          alt={s.displayTitle} 
                          className="w-full h-48 md:h-auto object-cover md:rounded-l-xl transform group-hover:scale-105 transition-transform duration-700 ease-out" 
                        />
                      </div>
                    )}
                    
                    <div className={s.image ? 'md:w-3/5 order-2 md:order-2 p-6 md:p-8 lg:p-12 text-center md:text-left relative z-20' : 'w-full order-2 p-6 md:p-8 lg:p-12 text-center md:text-left relative z-20'}>
                      <div className="mb-6 md:mb-8 flex flex-col items-center md:items-start overflow-hidden">
                        <div className="flex items-center gap-3 mb-4 flex-col md:flex-row w-full">
                          <s.icon className="w-5 h-5 md:w-6 md:h-6 text-[#072D42] group-hover:text-white transition-all duration-500 ease-out transform group-hover:scale-110 flex-shrink-0" />
                          
                          <h2 className="font-playfair text-2xl md:text-3xl lg:text-4xl font-normal tracking-wide text-[#072D42] group-hover:text-white transition-all duration-500 ease-out transform translate-y-0 group-hover:-translate-y-1">
                            {s.displayTitle}
                          </h2>
                        </div>
                        
                        <div className="h-px w-16 md:w-20 bg-[#072D42] group-hover:bg-white transition-all duration-500 ease-out transform origin-left md:ml-8 mx-auto md:mx-0 group-hover:scale-x-150"></div>
                      </div>
                      
                      <div className="font-inter text-base md:text-lg leading-relaxed font-light tracking-wide text-[#072D42]/95 group-hover:text-white/95 transition-all duration-700 ease-out transform translate-x-0 group-hover:translate-x-2 max-w-prose mx-auto md:mx-0 text-justify md:text-left relative z-30">
                        {s.body}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
            
            <div 
              id={howItStartedSection.id}
              ref={(el) => (sectionRefs.current[howItStartedSection.id] = el)}
              className={`
                scroll-mt-24 
                transform transition-all duration-700 ease-out
                ${revealedSections[howItStartedSection.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}
              `}
            >
              <div className="mb-8 text-center md:text-left">
                <div className="flex items-center gap-3 mb-4 flex-col md:flex-row justify-center md:justify-start">
                  <howItStartedSection.icon className="w-5 h-5 md:w-6 md:h-6 text-[#072D42]" />
                  <h2 className="font-playfair text-2xl md:text-3xl lg:text-4xl font-normal tracking-wide text-[#072D42]">
                    {howItStartedSection.displayTitle}
                  </h2>
                </div>
                <div className="h-px w-16 md:w-20 bg-[#072D42] mx-auto md:ml-8"></div>
              </div>
              <div className="font-inter text-justify md:text-left">
                {howItStartedSection.body}
              </div>
            </div>
          </section>
        </div>

        <footer className="mt-16 md:mt-20 pt-6 md:pt-8 border-t border-[#072D42]/20 text-center max-w-5xl mx-auto">
          <p className="text-sm font-light tracking-wide text-[#072D42]/60 font-montserrat">
            © {new Date().getFullYear()} Archivo Histórico Empresarial Boliviano
          </p>
        </footer>
      </main>

      {/* Estilos para animaciones */}
      <style jsx>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(-10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fadeIn {
          animation: fadeIn 0.3s ease-out;
        }
      `}</style>
    </div>
  );
};

export default AboutUsPage;
